// ==================================================
// KPI 1 - Catalog Quality Score (Data Quality)
// ==================================================
const products = $input.first().json.products;
const total = products.length;

// % productos con brand
const withBrand = products.filter(p => p.brand && p.brand.trim() !== '').length;
const pctBrand = withBrand / total;

// % productos con images (no vacío)
const withImages = products.filter(p => Array.isArray(p.images) && p.images.length > 0).length;
const pctImages = withImages / total;

// % productos con dimensions completas
const withDimensions = products.filter(p =>
  p.dimensions &&
  p.dimensions.width !== undefined &&
  p.dimensions.height !== undefined &&
  p.dimensions.depth !== undefined
).length;
const pctDimensions = withDimensions / total;

// KPI general = promedio de los 3 porcentajes
const catalogQualityScore = (pctBrand + pctImages + pctDimensions) / 3;

// ==================================================
// KPI 2 - Score de Prioridad de Reposición
// priority = low_stock_flag * rating * price
// low_stock_flag = 1 si stock < 10, sino 0
// ==================================================
const productsWithPriority = products.map(p => {
  const lowStockFlag = p.stock < 10 ? 1 : 0;
  const priorityScore = lowStockFlag * (p.rating || 0) * (p.price || 0);
  return {
    id: p.id,
    title: p.title,
    stock: p.stock,
    rating: p.rating,
    price: p.price,
    brand: p.brand,
    sku: p.sku,
    lowStockFlag,
    priorityScore
  };
});

// Top 5 productos críticos (mayor priority score, solo low_stock)
const top5Critical = productsWithPriority
  .filter(p => p.lowStockFlag === 1)
  .sort((a, b) => b.priorityScore - a.priorityScore)
  .slice(0, 5);

// Promedio de priority score (solo productos con low stock)
const lowStockProducts = productsWithPriority.filter(p => p.lowStockFlag === 1);
const avgPriorityScore = lowStockProducts.length > 0
  ? lowStockProducts.reduce((sum, p) => sum + p.priorityScore, 0) / lowStockProducts.length
  : 0;

const now = new Date().toISOString();

return [{
  json: {
    timestamp: now,
    totalProducts: total,
    // KPI 1
    catalogQualityScore: parseFloat(catalogQualityScore.toFixed(4)),
    pctBrand: parseFloat(pctBrand.toFixed(4)),
    pctImages: parseFloat(pctImages.toFixed(4)),
    pctDimensions: parseFloat(pctDimensions.toFixed(4)),
    // KPI 2
    avgPriorityScore: parseFloat(avgPriorityScore.toFixed(4)),
    top5Critical,
    // Umbrales
    thresholdQuality: 0.80,   // alerta si quality < 80%
    thresholdPriority: 50.0   // alerta si avg priority > 50
  }
}];

