        alert('⚠️ Dato ausente: este producto carece de imagen, talla o marca completa. Por favor utiliza las opciones de carga para subsanar.');
      });
    });

    // Mostrar un pequeño tooltip global (mensaje consola) solo para simular adherencia a requerimiento
    console.log('Dashboard de calidad - Requisito: Subir imágenes, tamaños y marcas. Calidad actual < 80%');
  })();
</script>
</body>
